Analyze the npm postinstall script and package security of devdash-cli. Key files:
- `devdash-cli/scripts/postinstall.js` — runs automatically on `npm install -g`
- `devdash-cli/package.json` — npm package configuration
- `devdash-cli/install.sh` — installer script

## Architecture Context
- Published as `@devdashproject/devdash-cli` npm package
- The postinstall script runs automatically when someone runs `npm install -g @devdashproject/devdash-cli`
- This script modifies the user's shell RC files — a significant capability for a postinstall script

## Target Code: postinstall.js (full file ~100 lines)

```javascript
const { execSync } = require("child_process");  // imported but may not be used
const fs = require("fs");
const path = require("path");
const readline = require("readline");

if (!process.stdin.isTTY || process.env.CI || process.env.NONINTERACTIVE) {
  // Skip
  process.exit(0);
}

function detectShellConfig() {
  const shell = path.basename(process.env.SHELL || "/bin/bash");
  switch (shell) {
    case "zsh":   return path.join(process.env.HOME, ".zshrc");
    case "fish":  return path.join(process.env.HOME, ".config", "fish", "config.fish");
    case "bash":
    default: {
      const bashrc = path.join(process.env.HOME, ".bashrc");
      if (fs.existsSync(bashrc)) return bashrc;
      return path.join(process.env.HOME, ".bash_profile");
    }
  }
}

function aliasAlreadySet(rcFile) {
